        // Redis에 우선순위 기반 ZSET 추가
        redisTemplate.opsForZSet().add(
            queueKey,
            userId,
            priority.toDouble()
        )
    }

    fun dequeueUser(userId: String) {
        // Redis에서 즉시 제거
        redisTemplate.opsForZSet().remove(queueKey, userId)

