        // CompletableFuture.runAsync { ... }
    }

    // 주기적 동기화 (예: 1분마다)
    @Scheduled(fixedRate = 60000)
    fun syncQueueToMySQL() {
        val redisQueue = redisTemplate.opsForZSet()
            .range(queueKey, 0, -1) ?: emptySet()

        // MySQL의 ACTIVE 큐와 비교하여 불일치 항목 제거
    }
}
```

#### B. 큐 상태 다이어그램

```
┌─────────────────────────────────────────────────┐
│ 사용자 매칭 요청                                 │
└────────────────┬────────────────────────────────┘
                 │
                 v
        ┌────────────────────┐
        │ Redis ZSET에 추가   │ (즉시 처리)
        │ (우선순위 기반)     │
        └────────┬───────────┘
                 │
                 v
        ┌────────────────────┐
        │ MySQL에 영구 저장   │ (비동기)
        │ (감사/복구용)      │
        └────────┬───────────┘
                 │
                 v
        ┌────────────────────┐
        │ 매칭 알고리즘 실행  │
        │ (1초마다)          │
        └────────┬───────────┘
                 │
        ┌────────┴─────────────┐
        │                      │
        v                      v
    매칭 성공          매칭 실패/타임아웃
    (30분 후)         (30분 후)
        │                      │
        v                      v
    대기열 제거          대기열 제거
```

---

### 종합 분석 요약

| 항목 | 상태 | 설명 |
|------|------|------|
| **코드 존재 여부** | 없음 | 템플릿/스켈레톤 프로젝트 |
| **권장 구조** | 있음 | Develop, Entity-Skill, GraphQL-Skill 문서 참고 |
| **DB 구조** | MySQL + Redis + DynamoDB | 각각 역할 분담 |
| **매칭 알고리즘** | 미구현 | QueryDSL 기반 복합 조건 조회 권장 |
| **성능 최적화** | Fetch Join, 인덱스, Redis 캐싱 | 3가지 기본 전략 |
| **대기열 구현** | Redis ZSET 권장 | MySQL 백업 동기화 |

---

### 다음 단계 (액션 아이템)

1. **Entity 설계 완료** - `CallMatchEntity`, `MatchQueueEntity` 작성
2. **Repository 구현** - QueryDSL 기반 복합 조건 쿼리
3. **Service 로직** - 매칭 알고리즘, 우선순위 계산
4. **Redis 통합** - 대기열 관리, 캐싱 전략
5. **성능 테스트** - N+1 쿼리 검증, 응답시간 측정
6. **DynamoDB** - 실시간 세션 로깅 (선택사항)

프로젝트 가이드에 따라 정확한 구현이 필요하시면, 각 계층별로 코드 작성을 지원하겠습니다.

