    val ageGroup: String,        // "20s" | "30s" | "40s"
    val preferGender: String,    // "M" | "F" | "ANY"

    @Enumerated(EnumType.STRING)
    var status: MatchingStatus = MatchingStatus.WAITING,

    @CreatedDate
