```

```kotlin
// infrastructure/src/main/kotlin/com/maum/backend/matching/MatchingQueueRedisRepository.kt
@Repository
class MatchingQueueRedisRepository(
    private val redisTemplate: RedisTemplate<String, String>
) {
    companion object {
        private const val QUEUE_KEY_PREFIX = "matching:queue"
        private const val TTL_MINUTES = 30L
        private const val MAX_MATCH_CANDIDATES = 10L
    }

    // 대기열 진입: score = 현재 timestamp (오래 기다린 순 우선)
    fun enqueue(userId: String, gender: String, ageGroup: String) {
        val key = buildQueueKey(gender, ageGroup)
        val score = System.currentTimeMillis().toDouble()
        redisTemplate.opsForZSet().add(key, userId, score)
        redisTemplate.expire(key, TTL_MINUTES, TimeUnit.MINUTES)
    }

    // 매칭 후보 조회: score 오름차순(오래 기다린 순) 상위 N명
    fun findCandidates(preferGender: String, myAgeGroup: String): List<String> {
        val key = buildQueueKey(preferGender, myAgeGroup)
        return redisTemplate.opsForZSet()
            .range(key, 0, MAX_MATCH_CANDIDATES - 1)
            ?.toList() ?: emptyList()
    }

    // 원자적 매칭 처리: Lua 스크립트로 race condition 방지
    fun atomicMatch(userId1: String, userId2: String, gender: String, ageGroup: String): Boolean {
        val script = """
            local key = KEYS[1]
            local user1 = ARGV[1]
            local user2 = ARGV[2]
            -- 두 사용자가 모두 대기열에 존재하는지 확인
            if redis.call('zscore', key, user1) and redis.call('zscore', key, user2) then
                redis.call('zrem', key, user1)
                redis.call('zrem', key, user2)
                return 1
            end
            return 0
        """.trimIndent()

        val result = redisTemplate.execute(
            RedisScript.of(script, Long::class.java),
            listOf(buildQueueKey(gender, ageGroup)),
            userId1, userId2
        )
        return result == 1L
    }

    fun dequeue(userId: String, gender: String, ageGroup: String) {
        redisTemplate.opsForZSet().remove(buildQueueKey(gender, ageGroup), userId)
    }

    fun getWaitingCount(gender: String, ageGroup: String): Long =
        redisTemplate.opsForZSet().size(buildQueueKey(gender, ageGroup)) ?: 0L

    private fun buildQueueKey(gender: String, ageGroup: String) =
        "$QUEUE_KEY_PREFIX:$gender:$ageGroup"
}
```

