## 2. DB 인덱스 전략 (MySQL 8.0.28)

### 매칭 관련 핵심 테이블 인덱스

```sql
-- maum.matching_queue 테이블
CREATE TABLE matching_queue (
    id           VARCHAR(36) PRIMARY KEY,
    user_id      VARCHAR(36)  NOT NULL,
    gender       VARCHAR(1)   NOT NULL,   -- 'M', 'F'
    age_group    VARCHAR(5)   NOT NULL,   -- '20s', '30s'
    prefer_gender VARCHAR(1)  NOT NULL,
    status       VARCHAR(20)  NOT NULL DEFAULT 'WAITING',
    created_at   DATETIME(3)  NOT NULL,
    updated_at   DATETIME(3)  NOT NULL
);

-- 인덱스 전략
-- 1. 매칭 후보 조회용 복합 인덱스 (카디널리티 높은 순서 배치)
CREATE INDEX idx_matching_queue_status_gender_age
    ON matching_queue (status, gender, age_group, created_at);

-- 2. 사용자별 대기 상태 조회
CREATE INDEX idx_matching_queue_user_status
    ON matching_queue (user_id, status);

-- maum.call_history 테이블
CREATE TABLE call_history (
    id           VARCHAR(36) PRIMARY KEY,
    caller_id    VARCHAR(36)  NOT NULL,
    callee_id    VARCHAR(36)  NOT NULL,
    status       VARCHAR(20)  NOT NULL,
    started_at   DATETIME(3),
    ended_at     DATETIME(3),
    created_at   DATETIME(3)  NOT NULL,
    updated_at   DATETIME(3)  NOT NULL
);

-- 3. 최근 통화 이력 조회 (중복 매칭 방지용)
CREATE INDEX idx_call_history_caller_created
    ON call_history (caller_id, created_at DESC);

-- 4. 양방향 통화 이력 조회용 (Covering Index)
CREATE INDEX idx_call_history_participants
    ON call_history (caller_id, callee_id, created_at DESC);

-- maum.user_profile 테이블 (매칭 필터용)
-- 5. 활성 사용자 프로필 필터링
CREATE INDEX idx_user_profile_active_gender_age
    ON user_profile (is_active, gender, age_group, last_active_at DESC);
