## 3. 비동기 처리 방식 (Kotlin Coroutine)

### Before - 동기 블로킹 방식

```kotlin
// 안티패턴: 모든 I/O가 순차 블로킹
fun requestMatching(userId: String): MatchingResult {
    val userProfile = userRepository.findById(userId)         // DB I/O 블로킹 ~30ms
    val callHistory = callHistoryRepository.findRecent(userId) // DB I/O 블로킹 ~20ms
    val blockedUsers = blockRepository.findByUserId(userId)   // DB I/O 블로킹 ~15ms
    val candidates = matchingQueue.findCandidates(userProfile) // Redis I/O 블로킹 ~5ms
    // 총 순차 대기: ~70ms
    return performMatch(userProfile, callHistory, blockedUsers, candidates)
}
```

### After - Coroutine 병렬 조회

```kotlin
// application/src/main/kotlin/com/maum/backend/service/matching/MatchingService.kt
@Service
class MatchingService(
    private val userProfileRepository: UserProfileRepository,
    private val callHistoryRepository: CallHistoryRepository,
    private val blockRepository: BlockRepository,
    private val matchingQueueRedis: MatchingQueueRedisRepository,
    private val matchingQueueRepository: MatchingQueueRepository,
) {
    // suspend 함수: 비동기 처리 진입점
    suspend fun requestMatching(userId: String): MatchingResult =
        coroutineScope {
            // 독립적인 I/O를 병렬 실행
            val userProfileDeferred = async(Dispatchers.IO) {
                userProfileRepository.findByUserId(userId)
                    ?: throw NotFoundException("사용자 프로필 없음: $userId")
            }
            val callHistoryDeferred = async(Dispatchers.IO) {
                callHistoryRepository.findRecentByUserId(userId, limit = 50)
            }
            val blockedUsersDeferred = async(Dispatchers.IO) {
                blockRepository.findBlockedUserIdsByUserId(userId)
            }

            // 병렬 완료 대기: 가장 느린 작업 시간만큼만 소요
            val userProfile = userProfileDeferred.await()
            val recentCallHistory = callHistoryDeferred.await()
            val blockedUserIds = blockedUsersDeferred.await()

            // Redis에서 후보 조회 (이미 빠름)
            val candidates = matchingQueueRedis.findCandidates(
                preferGender = userProfile.preferGender,
                myAgeGroup = userProfile.ageGroup
            )

            // 필터링 후 매칭
            val filteredCandidates = candidates
                .filterNot { it in blockedUserIds }
                .filterNot { id -> recentCallHistory.any { it.partnerId == id } }

            performAtomicMatch(userId, userProfile, filteredCandidates)
        }

    private suspend fun performAtomicMatch(
        userId: String,
        userProfile: UserProfileEntity,
        candidates: List<String>
    ): MatchingResult {
        for (candidateId in candidates) {
            val matched = matchingQueueRedis.atomicMatch(
                userId1 = userId,
                userId2 = candidateId,
                gender = userProfile.gender,
                ageGroup = userProfile.ageGroup
            )
            if (matched) {
                // 비동기로 DB 기록 (응답 지연 없이)
                withContext(Dispatchers.IO) {
                    saveMatchHistory(userId, candidateId)
                }
                return MatchingResult.Matched(partnerId = candidateId)
            }
        }
        // 후보 없으면 대기열 진입
        matchingQueueRedis.enqueue(userId, userProfile.gender, userProfile.ageGroup)
        return MatchingResult.Waiting
    }
}
```

```kotlin
