// infrastructure/src/main/kotlin/com/maum/backend/query/MatchingQueryRepository.kt
@Repository
class MatchingQueryRepository(
    private val queryFactory: JPAQueryFactory
) {
    // 매칭 후보 정보를 한 번의 JOIN 쿼리로 조회 (N+1 원천 차단)
    fun findMatchingCandidateProfiles(userIds: List<String>): List<MatchingCandidateDto> {
        val user = QUserProfileEntity.userProfileEntity
        val callStats = QUserCallStatsEntity.userCallStatsEntity

        return queryFactory
            .select(
                Projections.constructor(
                    MatchingCandidateDto::class.java,
                    user.userId,
                    user.nickname,
                    user.gender,
                    user.ageGroup,
                    user.profileImageUrl,
                    callStats.averageRating
                )
            )
            .from(user)
            .leftJoin(callStats).on(callStats.userId.eq(user.userId))
            .where(user.userId.`in`(userIds))
            .fetch()
    }
}

data class MatchingCandidateDto(
    val userId: String,
    val nickname: String,
    val gender: String,
    val ageGroup: String,
    val profileImageUrl: String?,
    val averageRating: Double?
)
