}

// domain/src/main/kotlin/com/maum/backend/repository/user/UserProfileRepository.kt
interface UserProfileRepository : JpaRepository<UserProfileEntity, String> {

    // ID 목록 In-Batch 조회: 단일 쿼리로 N개 프로필 조회
    @Query("SELECT u FROM UserProfileEntity u WHERE u.userId IN :userIds")
    fun findAllByUserIdIn(@Param("userIds") userIds: List<String>): List<UserProfileEntity>

    fun findByUserId(userId: String): UserProfileEntity?
}
