## 5. 캐싱 전략

### Redis 캐시 적용 지점 및 TTL 설계

```kotlin
// infrastructure/src/main/kotlin/com/maum/backend/cache/UserProfileCacheService.kt
@Service
class UserProfileCacheService(
    private val redisTemplate: RedisTemplate<String, String>,
    private val objectMapper: ObjectMapper,
    private val userProfileRepository: UserProfileRepository,
) {
    companion object {
        // 캐시 키 설계
        private const val USER_PROFILE_KEY = "cache:user:profile:{userId}"
        private const val BLOCK_LIST_KEY = "cache:user:blocklist:{userId}"
        private const val CALL_STATS_KEY = "cache:user:callstats:{userId}"

        // TTL 전략: 변경 빈도에 따라 차등 적용
        private val PROFILE_TTL = Duration.ofMinutes(10)   // 프로필: 10분 (변경 드묾)
        private val BLOCKLIST_TTL = Duration.ofMinutes(5)  // 차단목록: 5분 (실시간성 필요)
        private val CALL_STATS_TTL = Duration.ofHours(1)   // 통화 통계: 1시간 (집계 데이터)
    }

    suspend fun getUserProfile(userId: String): UserProfileDto =
        withContext(Dispatchers.IO) {
            val cacheKey = USER_PROFILE_KEY.replace("{userId}", userId)

            // Cache-Aside 패턴
            redisTemplate.opsForValue().get(cacheKey)
                ?.let { objectMapper.readValue(it, UserProfileDto::class.java) }
                ?: run {
                    val profile = userProfileRepository.findByUserId(userId)
                        ?.toDto() ?: throw NotFoundException("프로필 없음: $userId")
                    redisTemplate.opsForValue().set(
                        cacheKey,
                        objectMapper.writeValueAsString(profile),
                        PROFILE_TTL
                    )
                    profile
                }
        }

    // 캐시 무효화: 프로필 수정 시 호출
    fun invalidateUserProfile(userId: String) {
        val cacheKey = USER_PROFILE_KEY.replace("{userId}", userId)
        redisTemplate.delete(cacheKey)
    }

    // 차단 목록 캐시 (매칭 필터링에 매우 자주 사용)
    suspend fun getBlockedUserIds(userId: String): Set<String> =
        withContext(Dispatchers.IO) {
            val cacheKey = BLOCK_LIST_KEY.replace("{userId}", userId)

            redisTemplate.opsForSet().members(cacheKey)?.ifEmpty { null }
                ?: run {
                    val blockedIds = blockRepository.findBlockedUserIdsByUserId(userId).toSet()
                    if (blockedIds.isNotEmpty()) {
                        redisTemplate.opsForSet().add(cacheKey, *blockedIds.toTypedArray())
                        redisTemplate.expire(cacheKey, BLOCKLIST_TTL)
                    }
                    blockedIds
                }
        }
}
```

